#include <bits/stdc++.h>
using namespace std;


int main() {
    int a, b;
    cin >> a >> b;

    int max_exp_so_far = -1;
    int result_num = a;

    for (int i = a; i <= b; ++i) {
        if (i == 0) continue;

        int current_num = i;
        int current_exp = 0;

        while (current_num % 2 == 0) {
            current_exp++;
            current_num /= 2;
        }

        if (current_exp > max_exp_so_far) {
            max_exp_so_far = current_exp;
            result_num = i;
        }
    }
    cout << result_num << "\n";
    return 0;
}

